     1→// Interview Practice Page JavaScript
     2→
     3→let practiceState = {
     4→  currentQuestion: null,
     5→  stats: null,
     6→  user: null
     7→};
     8→
     9→// Initialize
    10→document.addEventListener('DOMContentLoaded', async () => {
    11→  const user = await checkAuth();
    12→  if (!user) {
    13→    window.location.href = '/login.html';
    14→    return;
    15→  }
    16→
    17→  practiceState.user = user;
    18→
    19→  // Setup tabs
    20→  setupTabs();
    21→
    22→  // Load initial data
    23→  await loadStats();
    24→  await loadQuestionLibrary();
    25→});
    26→
    27→// Setup tab switching
    28→function setupTabs() {
    29→  const tabs = document.querySelectorAll('.tab');
    30→  tabs.forEach(tab => {
    31→    tab.addEventListener('click', () => {
    32→      const tabName = tab.dataset.tab;
    33→
    34→      // Update active states
    35→      tabs.forEach(t => t.classList.remove('active'));
    36→      tab.classList.add('active');
    37→
    38→      document.querySelectorAll('.tab-content').forEach(content => {
    39→        content.classList.remove('active');
    40→      });
    41→      document.getElementById(`${tabName}-content`).classList.add('active');
    42→
    43→      // Load content if needed
    44→      if (tabName === 'progress') {
    45→        loadProgressDashboard();
    46→      }
    47→    });
    48→  });
    49→}
    50→
    51→// Load practice stats
    52→async function loadStats() {
    53→  try {
    54→    const data = await apiCall('/interviews/practice/stats');
    55→
    56→    if (data && data.stats) {
    57→      practiceState.stats = data.stats;
    58→
    59→      document.getElementById('stat-total').textContent = data.stats.total_questions || 0;
    60→      document.getElementById('stat-avg').textContent =
    61→        data.stats.average_score ? `${data.stats.average_score.toFixed(1)}/10` : '—';
    62→
    63→      // Calculate improvement
    64→      if (data.stats.improvement) {
    65→        const improvement = data.stats.improvement;
    66→        const sign = improvement > 0 ? '+' : '';
    67→        document.getElementById('stat-improvement').textContent = `${sign}${improvement.toFixed(1)}%`;
    68→      } else {
    69→        document.getElementById('stat-improvement').textContent = '—';
    70→      }
    71→
    72→      document.getElementById('stat-streak').textContent = data.stats.day_streak || 0;
    73→    }
    74→  } catch (err) {
    75→    console.error('Failed to load stats:', err);
    76→  }
    77→}
    78→
    79→// Load question library
    80→async function loadQuestionLibrary() {
    81→  showLoading('Loading question library...');
    82→
    83→  try {
    84→    const data = await apiCall('/interviews/practice/library');
    85→
    86→    if (data && data.questions) {
    87→      renderQuestionLibrary(data.questions);
    88→    }
    89→
    90→    hideLoading();
    91→  } catch (err) {
    92→    console.error('Failed to load question library:', err);
    93→    hideLoading();
    94→
    95→    document.getElementById('question-library').innerHTML = `
    96→      <div class="empty-state">
    97→        <div class="empty-state-icon">📚</div>
    98→        <h3>Question Library</h3>
    99→        <p>Unable to load questions. Please try again later.</p>
   100→      </div>
   101→    `;
   102→  }
   103→}
   104→
   105→// Render question library
   106→function renderQuestionLibrary(questions) {
   107→  const container = document.getElementById('question-library');
   108→
   109→  if (questions.length === 0) {
   110→    container.innerHTML = `
   111→      <div class="empty-state">
   112→        <div class="empty-state-icon">📚</div>
   113→        <h3>No Questions Available</h3>
   114→        <p>Check back soon for practice questions!</p>
   115→      </div>
   116→    `;
   117→    return;
   118→  }
   119→
   120→  container.innerHTML = questions.map((q, idx) => `
   121→    <div class="question-card" data-question-idx="${idx}">
   122→      <span class="question-category-badge category-${q.category}">
   123→        ${q.category.charAt(0).toUpperCase() + q.category.slice(1)}
   124→      </span>
   125→      <div class="question-text">${q.question}</div>
   126→      <div class="question-meta">
   127→        <span>💪 ${q.difficulty}</span>
   128→        ${q.times_practiced ? `<span>📝 Practiced ${q.times_practiced} times</span>` : ''}
   129→        ${q.last_score ? `<span>⭐ Last score: ${q.last_score}/10</span>` : ''}
   130→      </div>
   131→    </div>
   132→  `).join('');
   133→
   134→  // Attach click handlers safely (no inline JSON in onclick)
   135→  container.querySelectorAll('.question-card[data-question-idx]').forEach(card => {
   136→    card.addEventListener('click', () => {
   137→      const idx = parseInt(card.dataset.questionIdx);
   138→      openPracticeModal(questions[idx]);
   139→    });
   140→  });
   141→}
   142→
   143→// Open practice modal with question
   144→function openPracticeModal(question) {
   145→  practiceState.currentQuestion = question;
   146→
   147→  document.getElementById('modal-question-text').textContent = question.question;
   148→  document.getElementById('modal-category-badge').textContent =
   149→    `${question.category.charAt(0).toUpperCase() + question.category.slice(1)} • ${question.difficulty}`;
   150→
   151→  document.getElementById('practice-response').value = '';
   152→  document.getElementById('practice-question-view').style.display = 'block';
   153→  document.getElementById('coaching-result').style.display = 'none';
   154→  document.getElementById('coaching-result').classList.remove('active');
   155→
   156→  document.getElementById('practice-modal').classList.add('active');
   157→}
   158→
   159→// Close practice modal
   160→function closePracticeModal() {
   161→  document.getElementById('practice-modal').classList.remove('active');
   162→  practiceState.currentQuestion = null;
   163→}
   164→
   165→// Submit practice response for coaching
   166→async function submitPracticeResponse() {
   167→  const response = document.getElementById('practice-response').value.trim();
   168→
   169→  if (!response) {
   170→    alert('Please provide a response before getting coaching.');
   171→    return;
   172→  }
   173→
   174→  if (response.length < 50) {
   175→    alert('Please provide a more detailed response (at least 50 characters).');
   176→    return;
   177→  }
   178→
   179→  showLoading('AI is analyzing your response...');
   180→
   181→  try {
   182→    const data = await apiCall('/interviews/practice/submit', {
